import{_ as l,o as t,c as i,a2 as e}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1992年巴菲特致股东信核心要点","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1992年/核心总结.md","filePath":"01_letters/1992年/核心总结.md"}'),r={name:"01_letters/1992年/核心总结.md"};function o(h,a,d,u,n,s){return t(),i("div",null,[...a[0]||(a[0]=[e('<h1 id="_1992年巴菲特致股东信核心要点" tabindex="-1">1992年巴菲特致股东信核心要点 <a class="header-anchor" href="#_1992年巴菲特致股东信核心要点" aria-label="Permalink to &quot;1992年巴菲特致股东信核心要点&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长20.3%</li><li>账面价值从$19增长至$7,745</li><li>28年复合增长率：23.6%</li><li>发行6,106股新股（债券转换）</li></ul><hr><h2 id="业绩衡量标准" tabindex="-1">业绩衡量标准 <a class="header-anchor" href="#业绩衡量标准" aria-label="Permalink to &quot;业绩衡量标准&quot;">​</a></h2><h3 id="波动性是常态" tabindex="-1">波动性是常态 <a class="header-anchor" href="#波动性是常态" aria-label="Permalink to &quot;波动性是常态&quot;">​</a></h3><ul><li>GAAP要求按市值计价</li><li>股价波动导致年度业绩剧烈波动</li><li>衡量标准：长打率而非打击率</li></ul><h3 id="与标普500比较的三个要点" tabindex="-1">与标普500比较的三个要点 <a class="header-anchor" href="#与标普500比较的三个要点" aria-label="Permalink to &quot;与标普500比较的三个要点&quot;">​</a></h3><ol><li>经营业务回报（不受股市影响）</li><li>税负劣势（公司税vs指数税前）</li><li>未来预期：指数回报将下降，规模拖累将增加</li></ol><hr><h2 id="所罗门插曲" tabindex="-1">所罗门插曲 <a class="header-anchor" href="#所罗门插曲" aria-label="Permalink to &quot;所罗门插曲&quot;">​</a></h2><h3 id="巴菲特担任临时董事长" tabindex="-1">巴菲特担任临时董事长 <a class="header-anchor" href="#巴菲特担任临时董事长" aria-label="Permalink to &quot;巴菲特担任临时董事长&quot;">​</a></h3><ul><li>1991年6月-1992年6月</li><li>所罗门声誉改善排名第二（311家公司中）</li><li>税前收益创纪录（比此前最高高34%）</li></ul><h3 id="关键人物" tabindex="-1">关键人物 <a class="header-anchor" href="#关键人物" aria-label="Permalink to &quot;关键人物&quot;">​</a></h3><ul><li>德里克·莫恩、鲍勃·德纳姆、唐·霍华德、约翰·麦克法兰</li><li>律师罗恩·奥尔森</li></ul><hr><h2 id="收购策略" tabindex="-1">收购策略 <a class="header-anchor" href="#收购策略" aria-label="Permalink to &quot;收购策略&quot;">​</a></h2><h3 id="亲吻蟾蜍-陷阱" tabindex="-1">&quot;亲吻蟾蜍&quot;陷阱 <a class="header-anchor" href="#亲吻蟾蜍-陷阱" aria-label="Permalink to &quot;&quot;亲吻蟾蜍&quot;陷阱&quot;">​</a></h3><ul><li>收购者被童话迷惑</li><li>高价买入差公司</li><li>最后计提重组费用</li><li>&quot;狂热在于当你忘记目标时还在加倍努力&quot;</li></ul><h3 id="正确方法" tabindex="-1">正确方法 <a class="header-anchor" href="#正确方法" aria-label="Permalink to &quot;正确方法&quot;">​</a></h3><ul><li>以合理价格购买好企业</li><li>而非以好价格购买合理企业</li></ul><h3 id="中央州赔偿公司收购" tabindex="-1">中央州赔偿公司收购 <a class="header-anchor" href="#中央州赔偿公司收购" aria-label="Permalink to &quot;中央州赔偿公司收购&quot;">​</a></h3><ul><li>年保费9000万美元，利润1000万</li><li>比尔·凯泽家族管理</li><li>与26年前国民赔偿公司收购类似</li></ul><hr><h2 id="透视盈利" tabindex="-1">透视盈利 <a class="header-anchor" href="#透视盈利" aria-label="Permalink to &quot;透视盈利&quot;">​</a></h2><h3 id="目标" tabindex="-1">目标 <a class="header-anchor" href="#目标" aria-label="Permalink to &quot;目标&quot;">​</a></h3><ul><li>2000年需达到18亿美元</li><li>1992年：6.04亿美元</li></ul><h3 id="主要被投资方留存收益" tabindex="-1">主要被投资方留存收益 <a class="header-anchor" href="#主要被投资方留存收益" aria-label="Permalink to &quot;主要被投资方留存收益&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>持股比例</th><th>未分配收益(M)</th></tr></thead><tbody><tr><td>首都城市/ABC</td><td>18.2%</td><td>70</td></tr><tr><td>可口可乐</td><td>7.1%</td><td>82</td></tr><tr><td>房地美</td><td>8.2%</td><td>29</td></tr><tr><td>GEICO</td><td>48.1%</td><td>34</td></tr><tr><td>通用动力</td><td>14.1%</td><td>11</td></tr><tr><td>吉列</td><td>10.9%</td><td>38</td></tr></tbody></table><hr><h2 id="保险业务" tabindex="-1">保险业务 <a class="header-anchor" href="#保险业务" aria-label="Permalink to &quot;保险业务&quot;">​</a></h2><h3 id="安德鲁飓风" tabindex="-1">安德鲁飓风 <a class="header-anchor" href="#安德鲁飓风" aria-label="Permalink to &quot;安德鲁飓风&quot;">​</a></h3><ul><li>保险业历史最大损失</li><li>伯克希尔损失约1.25亿美元</li><li>等于当年超级巨灾保费收入</li></ul><h3 id="浮存金成本" tabindex="-1">浮存金成本 <a class="header-anchor" href="#浮存金成本" aria-label="Permalink to &quot;浮存金成本&quot;">​</a></h3><ul><li>1992年：4.76%</li><li>长期国债收益率：7.39%</li><li>27年中22年击败国债利率</li></ul><hr><h2 id="普通股投资" tabindex="-1">普通股投资 <a class="header-anchor" href="#普通股投资" aria-label="Permalink to &quot;普通股投资&quot;">​</a></h2><h3 id="价值超过1亿美元的持仓" tabindex="-1">价值超过1亿美元的持仓 <a class="header-anchor" href="#价值超过1亿美元的持仓" aria-label="Permalink to &quot;价值超过1亿美元的持仓&quot;">​</a></h3><table tabindex="0"><thead><tr><th>公司</th><th>持股</th><th>市值(M)</th></tr></thead><tbody><tr><td>可口可乐</td><td>93,400,000股</td><td>3,911.1</td></tr><tr><td>GEICO</td><td>34,250,000股</td><td>2,226.3</td></tr><tr><td>吉列</td><td>24,000,000股</td><td>1,365.0</td></tr><tr><td>首都城市/ABC</td><td>3,000,000股</td><td>1,523.5</td></tr><tr><td>房地美</td><td>16,196,700股</td><td>783.5</td></tr><tr><td>富国银行</td><td>6,358,418股</td><td>485.6</td></tr></tbody></table><h3 id="通用动力投资" tabindex="-1">通用动力投资 <a class="header-anchor" href="#通用动力投资" aria-label="Permalink to &quot;通用动力投资&quot;">​</a></h3><ul><li>CEO比尔·安德斯的战略执行</li><li>巴菲特称之为&quot;非凡成就&quot;</li></ul><hr><h2 id="股票投资策略" tabindex="-1">股票投资策略 <a class="header-anchor" href="#股票投资策略" aria-label="Permalink to &quot;股票投资策略&quot;">​</a></h2><h3 id="选股四原则" tabindex="-1">选股四原则 <a class="header-anchor" href="#选股四原则" aria-label="Permalink to &quot;选股四原则&quot;">​</a></h3><ol><li>可以理解的企业</li><li>良好的长期前景</li><li>诚实有能力的管理层</li><li>有吸引力的价格（从&quot;非常有吸引力&quot;调整）</li></ol><h3 id="价值与成长" tabindex="-1">价值与成长 <a class="header-anchor" href="#价值与成长" aria-label="Permalink to &quot;价值与成长&quot;">​</a></h3><ul><li>&quot;成长始终是价值计算的一部分&quot;</li><li>&quot;价值投资&quot;这个词本身就是多余的</li><li>投资就是寻求至少足以证明支付合理的价值</li></ul><h3 id="价值公式" tabindex="-1">价值公式 <a class="header-anchor" href="#价值公式" aria-label="Permalink to &quot;价值公式&quot;">​</a></h3><p><strong>约翰·伯尔·威廉姆斯：</strong></p><blockquote><p>任何股票、债券或企业今天的价值，由在资产剩余寿命期间预期发生的现金流入和流出——以适当的利率折现——决定。</p></blockquote><h3 id="最好的企业" tabindex="-1">最好的企业 <a class="header-anchor" href="#最好的企业" aria-label="Permalink to &quot;最好的企业&quot;">​</a></h3><ul><li>能以非常高的回报率使用大量增量资本</li><li>持续很长时间</li></ul><h3 id="最差的企业" tabindex="-1">最差的企业 <a class="header-anchor" href="#最差的企业" aria-label="Permalink to &quot;最差的企业&quot;">​</a></h3><ul><li>必须以非常低的回报率使用越来越多资本</li></ul><hr><h2 id="投资风险" tabindex="-1">投资风险 <a class="header-anchor" href="#投资风险" aria-label="Permalink to &quot;投资风险&quot;">​</a></h2><h3 id="安全边际原则" tabindex="-1">安全边际原则 <a class="header-anchor" href="#安全边际原则" aria-label="Permalink to &quot;安全边际原则&quot;">​</a></h3><ul><li>本·格雷厄姆强调的基石</li><li>计算价值只略高于价格，不感兴趣购买</li></ul><h3 id="真正的风险" tabindex="-1">真正的风险 <a class="header-anchor" href="#真正的风险" aria-label="Permalink to &quot;真正的风险&quot;">​</a></h3><p>投资者必须评估的风险：</p><ol><li>企业长期经济特征的可确定程度</li><li>管理层能力的可评估程度</li><li>管理层股东导向的可信赖程度</li><li>企业的购买价格</li><li>税负和通胀水平</li></ol><h3 id="反对贝塔理论" tabindex="-1">反对贝塔理论 <a class="header-anchor" href="#反对贝塔理论" aria-label="Permalink to &quot;反对贝塔理论&quot;">​</a></h3><ul><li>贝塔衡量的是价格波动，不是业务风险</li><li>可口可乐、吉列的竞争优势在贝塔中无法体现</li><li>&quot;近似正确胜过精确错误&quot;</li></ul><hr><h2 id="能力圈原则" tabindex="-1">能力圈原则 <a class="header-anchor" href="#能力圈原则" aria-label="Permalink to &quot;能力圈原则&quot;">​</a></h2><h3 id="坚持做简单的事" tabindex="-1">坚持做简单的事 <a class="header-anchor" href="#坚持做简单的事" aria-label="Permalink to &quot;坚持做简单的事&quot;">​</a></h3><ul><li>无法预测快速变化行业的未来</li><li>30年前无法预见电视制造、计算机行业</li><li>当一根针摆在眼前时，为什么要大海捞针？</li></ul><h3 id="多元化的局限" tabindex="-1">多元化的局限 <a class="header-anchor" href="#多元化的局限" aria-label="Permalink to &quot;多元化的局限&quot;">​</a></h3><ul><li>广泛多元化适合不了解企业的投资者</li><li>了解企业的投资者应该集中</li></ul><hr><h2 id="公司治理" tabindex="-1">公司治理 <a class="header-anchor" href="#公司治理" aria-label="Permalink to &quot;公司治理&quot;">​</a></h2><h3 id="三种治理模式" tabindex="-1">三种治理模式 <a class="header-anchor" href="#三种治理模式" aria-label="Permalink to &quot;三种治理模式&quot;">​</a></h3><p><strong>第一种：无控股股东</strong></p><ul><li>董事应像存在一位单一缺席所有者那样行动</li><li>必要时更换管理层</li></ul><p><strong>第二种：控股股东兼任管理者（伯克希尔现状）</strong></p><ul><li>董事只能通过说服推动变革</li><li>无法改变时，外部董事应辞职</li></ul><p><strong>第三种：控股股东不参与管理（伯克希尔未来）</strong></p><ul><li>外部董事可直接向所有者报告</li><li>最有效的治理模式</li></ul><hr><h2 id="其他事项" tabindex="-1">其他事项 <a class="header-anchor" href="#其他事项" aria-label="Permalink to &quot;其他事项&quot;">​</a></h2><h3 id="股东指定捐赠" tabindex="-1">股东指定捐赠 <a class="header-anchor" href="#股东指定捐赠" aria-label="Permalink to &quot;股东指定捐赠&quot;">​</a></h3><ul><li>97%合格股份参与</li><li>捐赠760万美元，2810家慈善机构</li></ul><h3 id="公司费用" tabindex="-1">公司费用 <a class="header-anchor" href="#公司费用" aria-label="Permalink to &quot;公司费用&quot;">​</a></h3><ul><li>从560万降至420万美元</li><li>税后管理费用&lt;报告收益1%</li><li>无法律、人事、公关、投资者关系、战略规划部门</li></ul><h3 id="b夫人" tabindex="-1">B夫人 <a class="header-anchor" href="#b夫人" aria-label="Permalink to &quot;B夫人&quot;">​</a></h3><ul><li>99岁继续每周工作七天</li><li>将建筑土地卖给内布拉斯加家具城</li></ul><h3 id="股票分割立场" tabindex="-1">股票分割立场 <a class="header-anchor" href="#股票分割立场" aria-label="Permalink to &quot;股票分割立场&quot;">​</a></h3><ul><li>坚持1983年观点</li><li>帮助聚集最好的股东群体</li></ul><hr><h2 id="经典语录" tabindex="-1">经典语录 <a class="header-anchor" href="#经典语录" aria-label="Permalink to &quot;经典语录&quot;">​</a></h2><ol><li><p><strong>关于投资策略</strong>：</p><blockquote><p>&quot;练习不会完美；练习会使动作固化。&quot;</p></blockquote></li><li><p><strong>关于价值与成长</strong>：</p><blockquote><p>&quot;成长始终是价值计算的一个组成部分。&quot;</p></blockquote></li><li><p><strong>关于能力圈</strong>：</p><blockquote><p>&quot;当一根针就摆在眼前时，为什么要在大海捞针呢？&quot;</p></blockquote></li><li><p><strong>关于风险</strong>：</p><blockquote><p>&quot;近似正确胜过精确错误。&quot;</p></blockquote></li><li><p><strong>关于多元化</strong>：</p><blockquote><p>&quot;好东西太多了也可以很美妙。&quot;——梅·韦斯特</p></blockquote></li></ol><hr><h2 id="_1992年启示" tabindex="-1">1992年启示 <a class="header-anchor" href="#_1992年启示" aria-label="Permalink to &quot;1992年启示&quot;">​</a></h2><ol><li><strong>价值投资的本质</strong>：现金流折现，成长是价值的一部分</li><li><strong>安全边际</strong>：投资成功的基石</li><li><strong>能力圈</strong>：只投资理解的企业，坚持做简单的事</li><li><strong>集中投资</strong>：了解企业的投资者不应广泛分散</li><li><strong>公司治理</strong>：所有权结构决定治理有效性</li></ol>',94)])])}const b=l(r,[["render",o]]);export{c as __pageData,b as default};
